package com.aiaffiliate.infrastructure.notion.repository;
import com.aiaffiliate.application.reference.*;import com.aiaffiliate.domain.model.*;import com.aiaffiliate.domain.port.*;import com.aiaffiliate.infrastructure.notion.mapper.PinterestContentNotionMapper;import com.aiaffiliate.notion.client.NotionClient;import java.util.*;
/** Notion Pinterest 内容 Repository Adapter。 */
public class NotionPinterestContentRepository extends AbstractNotionRepository<PinterestContent> implements PinterestContentRepository{
 public NotionPinterestContentRepository(NotionClient c,PinterestContentNotionMapper m,EntityReferenceRepository r,NotionDatabaseLocator l){super(c,m,r,l,"pinterest-content","Pin ID");}
 public PinterestContent save(PinterestContent v){return saveEntity(v);}public PinterestContent update(PinterestContent v){return updateEntity(v);}public Optional<PinterestContent>findById(PinterestContentId id){return findEntity(id.value());}public List<PinterestContent>findAll(){return findAllEntities();}public List<PinterestContent>findByStatus(PinterestContentStatus s){return findAll().stream().filter(v->v.status()==s).toList();}public PageResult<PinterestContent>findPage(PageRequest p){return page(p);}public List<PinterestContent>findByOpportunityId(OpportunityId id){return findAll().stream().filter(v->v.opportunityId().equals(id)).toList();}public void archive(PinterestContentId id){archiveEntity(id.value());}}
